Symbols are <span class="tok-kw">new</span> primitive built-in object types introduced as part of ES6.
Symbols are often used to add unique property keys to an object that won't collide with keys any other code might add to the object, 
and which are hidden <span class="tok-kw">from</span> any mechanisms other code will typically use to access the object.

<span class="tok-kw">const</span> sym1 = Symbol();
<span class="tok-kw">const</span> sym = <span class="tok-kw">new</span> Symbol(); <span class="tok-cmt">// TypeError</span>
<span class="tok-kw">const</span> sym2 = Symbol("foo");
<span class="tok-kw">const</span> sym3 = Symbol("foo");
console.log(sym2 == sym3) <span class="tok-cmt">// false</span>
console.log(typeof sym2); <span class="tok-cmt">// symbol</span>

<span class="tok-cmt">//---- use cases of Symbols -----</span>
<span class="tok-kw">const</span> user = { name: "John Doe" };
<span class="tok-kw">const</span> secretId = Symbol(<span class="tok-str">'secret-id'</span>);

<span class="tok-cmt">// Add a property using a Symbol key</span>
user[secretId] = <span class="tok-str">'<span class="tok-num">12345</span>'</span>;

console.log(user.name); <span class="tok-cmt">// "John Doe"</span>
console.log(user[secretId]); <span class="tok-cmt">// "<span class="tok-num">12345</span>"</span>

<span class="tok-cmt">// The symbol property is ignored by standard enumeration</span>
<span class="tok-kw">for</span> (<span class="tok-kw">const</span> key in user) {
  console.log(key); <span class="tok-cmt">// Only logs "name"</span>
}

<span class="tok-cmt">//---- Can be used to create Enum like properties -----</span>
<span class="tok-kw">const</span> CarState = Object.freeze({
  DRIVE: Symbol(<span class="tok-str">'drive'</span>),
  IDLE: Symbol(<span class="tok-str">'idle'</span>),
});

<span class="tok-kw">function</span> changeCarState(car, newState) {
  <span class="tok-kw">if</span> (newState === CarState.DRIVE) {
    console.log(<span class="tok-str">'Wroom, wroom!'</span>);
    car.state = newState;
  } <span class="tok-kw">else</span> <span class="tok-kw">if</span> (newState === CarState.IDLE) {
    console.log(<span class="tok-str">'Waiting <span class="tok-kw">for</span> ya!'</span>);
    car.state = newState;
  }
}

class Account {
  <span class="tok-cmt">#balance = <span class="tok-num">0</span>; // Truly private field (ES2022 syntax)</span>

  set _creditAmount(amount) {
    <span class="tok-kw">if</span>(amount &gt; this.<span class="tok-cmt">#balance) {</span>
      console.log(<span class="tok-str">'Insufficient Amount'</span>);
      <span class="tok-kw">return</span>;
    }
    this.<span class="tok-cmt">#balance -= amount;</span>
  }

  <span class="tok-cmt">// Setter with validation</span>
  set _depositAmount(amount) {
    <span class="tok-kw">if</span> (amount &lt; <span class="tok-num">0</span>) {
      console.log("Balance cannot be negative!");
    } <span class="tok-kw">else</span> {
      this.<span class="tok-cmt">#balance += amount;</span>
    }
  }
}

<span class="tok-kw">const</span> acc = <span class="tok-kw">new</span> Account();
acc._depositAmount(<span class="tok-num">500</span>);
acc._creditAmount(<span class="tok-num">100</span>); <span class="tok-cmt">// Setter is used (validation runs)</span>
acc._depositAmount(-<span class="tok-num">50</span>); <span class="tok-cmt">// Output: Balance cannot be negative! (validation prevents bad data)</span>
